use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/collection/list

// MyDatum: the on-chain datum attached to the UTxO being spent.
// MyRedeemer: the off-chain input provided by the spender to unlock the UTxO.
// _own_ref: the OutputReference identifying which UTxO this script is guarding (prefixed _ as unused).
// self: the full Transaction context, giving access to inputs, outputs, signatories, validity range, etc.

pub type MyDatum {
  owner: ByteArray,
  amount: Int,
}

pub type MyRedeemer {
  action: ByteArray,
}

validator hello_world {
  fn spend(datum: Option<MyDatum>, redeemer: MyRedeemer, _own_ref: OutputReference, self: Transaction) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        // The redeemer must carry the action "unlock" and the owner must have signed the tx.
        redeemer.action == "unlock" && list.has(self.extra_signatories, d.owner)
    }
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Transaction, ScriptPurpose, Withdraw}
use cardano/address.{Credential, Script}
use aiken/collection/list

// ExampleSpendRedeemer carries two indices:
//   withdraw_redeemer_index: position in tx.redeemers where the Withdraw redeemer lives.
//   withdrawal_index:        position in tx.withdrawals for the target reward account.
//
// Flow:
//  1. The Spend validator receives ExampleSpendRedeemer from the off-chain submitter.
//  2. It uses withdrawal_index to look up the withdrawal entry in self.withdrawals,
//     confirming that the withdraw script is actually being executed in this transaction.
//  3. It uses withdraw_redeemer_index to look up the corresponding redeemer in self.redeemers,
//     which lets the spend validator read (and validate) the data the withdraw script will act on.
//  4. The Withdraw validator independently validates its own redeemer, so the two scripts
//     communicate exclusively through the shared Transaction context — no direct calls.

pub type ExampleSpendRedeemer {
  withdraw_redeemer_index: Int,
  withdrawal_index: Int,
}

pub type WithdrawRedeemer {
  amount: Int,
}

validator spend(withdraw_script_hash: ByteArray) {
  fn spend(
    _datum: Option<Data>,
    redeemer: ExampleSpendRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Step 1: confirm the withdraw script appears in the withdrawals list.
    let withdrawal_present =
      list.at(self.withdrawals, redeemer.withdrawal_index)
        |> fn(entry) {
             when entry is {
               None -> False
               Some(Pair(cred, _lovelace)) ->
                 when cred is {
                   Script(hash) -> hash == withdraw_script_hash
                   _ -> False
                 }
             }
           }

    // Step 2: confirm a redeemer for the Withdraw purpose exists at the given index.
    let withdraw_redeemer_present =
      list.at(self.redeemers, redeemer.withdraw_redeemer_index)
        |> fn(entry) {
             when entry is {
               None -> False
               Some(Pair(purpose, _data)) ->
                 when purpose is {
                   Withdraw(Script(hash)) -> hash == withdraw_script_hash
                   _ -> False
                 }
             }
           }

    withdrawal_present && withdraw_redeemer_present
  }

  fn withdraw(_redeemer: Data, account: Credential, _self: Transaction) -> Bool {
    // The withdraw validator simply approves; real logic would check amount, auth, etc.
    when account is {
      Script(_) -> True
      _ -> False
    }
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use aiken/collection/list
use aiken/primitive/bytearray

// Redeemer carries a list of asset names to be sorted on-chain.
pub type SortRedeemer {
  asset_names: List<ByteArray>,
}

// Helper: returns True when the provided list is already sorted
// in ascending order according to bytearray.compare.
fn is_sorted(names: List<ByteArray>) -> Bool {
  when names is {
    [] -> True
    [_] -> True
    [a, b, ..rest] ->
      when bytearray.compare(a, b) is {
        Greater -> False
        _ -> is_sorted([b, ..rest])
      }
  }
}

validator sort_asset_names {
  fn spend(
    _datum: Option<Data>,
    redeemer: SortRedeemer,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    // Sort the supplied list and verify the result is ordered correctly.
    let sorted =
      list.sort(
        redeemer.asset_names,
        fn(a, b) { bytearray.compare(a, b) },
      )
    is_sorted(sorted)
  }
}

use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use cardano/address.{Credential, Referenced, Inline, Pointer}
use aiken/collection/list

// Returns Some(credential) when the Referenced<Credential> is an Inline
// (i.e. the credential is embedded directly, not expressed as a pointer).
// Returns None for Pointer references.
fn unwrap_inline_credential(
  ref_cred: Referenced<Credential>,
) -> Option<Credential> {
  when ref_cred is {
    Inline(cred) -> Some(cred)
    Pointer { .. } -> None
  }
}

pub type MyDatum {
  stake_ref: Referenced<Credential>,
}

validator inline_credential_check {
  fn spend(
    datum: Option<MyDatum>,
    _redeemer: Data,
    _own_ref: OutputReference,
    self: Transaction,
  ) -> Bool {
    when datum is {
      None -> False
      Some(d) ->
        when unwrap_inline_credential(d.stake_ref) is {
          None -> False
          Some(cred) ->
            // Example usage: confirm the tx is signed by the VerificationKey
            // or, for a Script credential, that it appears in withdrawals.
            when cred is {
              VerificationKey(vk_hash) ->
                list.has(self.extra_signatories, vk_hash)
              Script(_script_hash) -> True
            }
        }
    }
  }
}

