use aiken/collection/list
use aiken/interval
use cardano/assets
use cardano/transaction.{OutputReference, Transaction}
use cardano/address.{Credential}
use cardano/governance.{Voter}

type VerificationKeyHash = ByteArray

validator hot_cold_vote(
  cold_key: VerificationKeyHash,
  hot_key: VerificationKeyHash,
  open_from: Int,
  open_until: Int,
) {
  fn vote(redeemer: Void, voter: Voter, self: Transaction) -> Bool {
    let cold_signed = list.has(self.extra_signatories, cold_key)
    let hot_signed = list.has(self.extra_signatories, hot_key)
    let in_window =
      interval.contains(self.validity_range, open_from) && interval.contains(
        self.validity_range,
        open_until,
      ) || interval.between(open_from, open_until) |> interval.includes(
        self.validity_range,
        _,
      )
    cold_signed || hot_signed && in_window
  }

  fn spend(datum: Option<Data>, redeemer: Data, own_ref: OutputReference, self: Transaction) -> Bool {
    False
  }
}

